library ieee;
use ieee.std_logic_1164.all;

entity comparator_64bit is
  port (
    a : in std_logic_vector(63 downto 0);
    b : in std_logic_vector(63 downto 0);
    equal : out std_logic;
    greater : out std_logic
  );
end entity comparator_64bit;

architecture rtl of comparator_64bit is
begin
  process(a, b)
  begin
    if a = b then
      equal <= '1';
      greater <= '0';
    elsif a > b then
      equal <= '0';
      greater <= '1';
    else
      equal <= '0';
      greater <= '0';
    end if;
  end process;
end architecture rtl;
